SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_dep_t_deposit_slip ON sc_dep_t_deposit_slip CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_dep_t_deposit_slip() RETURNS trigger AS $BODY$
BEGIN
--return ;
  --//--Insert 
  if coalesce(OLD.deposit_slip_no::text, '') = '' and (NEW.deposit_slip_no IS NOT NULL AND NEW.deposit_slip_no::text <> '') then
    if (pka.auto_entry) then
      NEW.officer_id := current_setting('app.login_id', true);
      NEW.branch_id := current_setting('app.login_br', true);
      NEW.client_name := pka_com_login.login_pc;
      NEW.entry_date := statement_timestamp();
      NEW.finance_date := pka_fin_daily.fp_finance_date('1');

      --Niorn 2020-07-21 KTM ต้องการยอดคงเหลือก่อนทำรายการฝากถอน
      select deposit_balance into STRICT NEW.old_balance from sc_dep_m_creditor where deposit_account_no = NEW.account_no;

    end if;

  end if;
  --//--Cancel
  if OLD.cancel_status = '0' and NEW.cancel_status = '1' then
   if (pka.auto_entry) then
        NEW.cancel_id := current_setting('app.login_id', true);
        NEW.cancel_pc := pka_com_login.login_pc;
        NEW.cancel_br := current_setting('app.login_br', true);
        NEW.cancel_time := statement_timestamp();
        NEW.finance_cancel := pka_fin_daily.fp_finance_date('1');
        NEW.cancel_deposit_date := pka_dep.fp_deposit_date; -- วันที่เงินฝาก ที่ยกเลิก
        --Niorn 2020-07-21 KTM ต้องการยอดคงเหลือหลังทำรายการปรับปรุง
        select deposit_balance into STRICT NEW.op_balance from sc_dep_m_creditor where deposit_account_no = NEW.account_no;
    end if;
  end if;

  --//--Default
  if coalesce(NEW.cancel_status::text, '') = '' or NEW.cancel_status !='1' then NEW.cancel_status := '0';end if;
  if coalesce(NEW.fin_status::text, '') = '' or NEW.fin_status != '1' then NEW.fin_status := '0';end if;
  if coalesce(NEW.month_due::text, '') = '' then NEW.month_due :=0;end if;
  if coalesce(NEW.op_tax::text, '') = '' then NEW.op_tax := 0;end if;
  if coalesce(NEW.op_receive_int::text, '') = '' then NEW.op_receive_int := 0;end if;
  if coalesce(NEW.op_ret_int::text, '') = '' then NEW.op_ret_int :=0;end if;
  if coalesce(NEW.fee_amount::text, '') = '' then NEW.fee_amount :=0;end if;
  if coalesce(NEW.working_day::text, '') = '' then NEW.working_day := pka_dep.fp_deposit_date;end if;
  if coalesce(NEW.adjust_fin_status::text, '') = '' or NEW.adjust_fin_status !='1' then NEW.adjust_fin_status := '0';end if;
  if coalesce(NEW.op_money_real::text, '') = '' or NEW.op_money_real <= 0 then NEW.op_money_real := NEW.deposit_by_cash_balance;end if;
  -- 
  if coalesce(NEW.print_slip::text, '') = '' or NEW.print_slip != '1' then NEW.print_slip :='0';end if;

 --Aero เพื่อออกรายงาน
  if coalesce(NEW.op_item_type::text, '') = ''  then
   case NEW.deposit_money_type_code
      when '01' then
        -----  01 = เงินสด
        case NEW.deposit_slip_type
          when 'DEP'then
            NEW.op_item_type := 'DCA';
          when 'OCA'then
            NEW.op_item_type := 'OCA';
          when 'WDR'then
            NEW.op_item_type := 'WCA';
          when 'CCA'then
            NEW.op_item_type := 'CCA';
          else
            NEW.op_item_type := NEW.deposit_slip_type;
        end case;

      when '02' then
        -----  02 = เช็ค
        case NEW.deposit_slip_type
          when 'DEP'then
            NEW.op_item_type := 'DCQ';
          when 'OCA'then
            NEW.op_item_type := 'OCQ';
          when 'WDR'then
            NEW.op_item_type := 'WCL';
          when 'CCA'then
            NEW.op_item_type := 'CCL';
          else
            NEW.op_item_type := NEW.deposit_slip_type;
        end case;

      when '04' then
        -----  04 = โอนผ่านธนาคาร
        case NEW.deposit_slip_type
          when 'DEP'then
            NEW.op_item_type := 'DTB';
          when 'OCA'then
            NEW.op_item_type := 'OTB';
          when 'WDR'then
            NEW.op_item_type := 'W/B';
          when 'CCA'then
            NEW.op_item_type := 'C/B';
          else
            NEW.op_item_type := NEW.deposit_slip_type;
        end case;

      when '05' then
        -----  05 = รายการโอนระหว่างบัญชี
        case NEW.deposit_slip_type
          when 'DEP'then
            NEW.op_item_type := 'DTD';
          when 'OCA'then
            NEW.op_item_type := 'OTD';
          when 'WDR'then
            NEW.op_item_type := 'W/T';
          when 'CCA'then
            NEW.op_item_type := 'C/T';
          else
            NEW.op_item_type := NEW.deposit_slip_type;
        end case;

      when '08' then
        -----  08 = หลายทาง
        case NEW.deposit_slip_type
          when 'DEP'then
            NEW.op_item_type := 'DMP';
          when 'OCA'then
            NEW.op_item_type := 'OMP';
          when 'WDR'then
            NEW.op_item_type := 'WMP';
          when 'CCA'then
            NEW.op_item_type := 'CMP';
          else
            NEW.op_item_type := NEW.deposit_slip_type;
        end case;

      else
        NEW.op_item_type := NEW.deposit_slip_type;
    end case;

  end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_dep_t_deposit_slip() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_dep_t_deposit_slip
	BEFORE INSERT OR UPDATE ON sc_dep_t_deposit_slip FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_dep_t_deposit_slip();

